// login.js — Login page with PIN pad
function renderLogin(container) {
  const settings = DB.get('settings') || {};
  const shopName = (settings.shop && settings.shop.name) ? settings.shop.name : 'Pangkas';
  let pin = '';

  container.innerHTML = `
    <div class="login-page">
      <div class="login-header">
        <div class="login-logo">💈</div>
        <h1 class="login-shop-name">${shopName}</h1>
        <p class="login-subtitle">Masukkan PIN untuk masuk</p>
      </div>

      <div class="pin-dots" id="pin-dots">
        <span class="pin-dot" data-i="0"></span>
        <span class="pin-dot" data-i="1"></span>
        <span class="pin-dot" data-i="2"></span>
        <span class="pin-dot" data-i="3"></span>
      </div>

      <div class="pin-error" id="pin-error" style="display:none;">PIN salah!</div>

      <div class="pin-pad" id="pin-pad">
        <button class="pin-key" data-val="1">1</button>
        <button class="pin-key" data-val="2">2</button>
        <button class="pin-key" data-val="3">3</button>
        <button class="pin-key" data-val="4">4</button>
        <button class="pin-key" data-val="5">5</button>
        <button class="pin-key" data-val="6">6</button>
        <button class="pin-key" data-val="7">7</button>
        <button class="pin-key" data-val="8">8</button>
        <button class="pin-key" data-val="9">9</button>
        <button class="pin-key pin-key-empty" disabled></button>
        <button class="pin-key" data-val="0">0</button>
        <button class="pin-key pin-key-del" data-val="del">⌫</button>
      </div>

      <div class="login-footer">Powered by Pangkas 💈</div>
    </div>
  `;

  function updateDots() {
    const dots = container.querySelectorAll('.pin-dot');
    dots.forEach((d, i) => {
      d.classList.toggle('filled', i < pin.length);
    });
  }

  function shakeAndClear() {
    const dotsEl = document.getElementById('pin-dots');
    const errEl = document.getElementById('pin-error');
    dotsEl.classList.add('shake');
    errEl.style.display = 'block';
    if (navigator.vibrate) navigator.vibrate(300);
    setTimeout(() => {
      dotsEl.classList.remove('shake');
      errEl.style.display = 'none';
      pin = '';
      updateDots();
    }, 800);
  }

  function attemptLogin() {
    const barbers = DB.get('barbers') || [];
    const matched = barbers.find(b => b.pin === pin);

    if (matched) {
      currentUser = matched;
      DB.set('currentUser', matched);

      // Check first run
      const settings = DB.get('settings');
      const services = DB.get('services') || [];
      if (!settings || !settings.shop || !settings.shop.name || services.length === 0) {
        navigateTo('onboarding');
      } else {
        navigateTo('home');
      }
    } else {
      // If no barbers exist, check for master PIN "0000"
      if (barbers.length === 0 && pin === '0000') {
        currentUser = { id: 'admin', name: 'Admin', role: 'admin', pin: '0000' };
        DB.set('currentUser', currentUser);
        navigateTo('onboarding');
      } else {
        shakeAndClear();
      }
    }
  }

  container.querySelector('#pin-pad').addEventListener('click', function(e) {
    const btn = e.target.closest('.pin-key');
    if (!btn || btn.disabled) return;

    const val = btn.dataset.val;

    if (val === 'del') {
      pin = pin.slice(0, -1);
      updateDots();
      return;
    }

    if (pin.length >= 4) return;
    pin += val;
    updateDots();

    if (pin.length === 4) {
      setTimeout(attemptLogin, 200);
    }
  });
}

// onboarding.js — First-run onboarding wizard
function renderOnboarding(container) {
  let step = 1;
  const data = {
    shopName: '',
    shopAddress: '',
    shopPhone: '',
    serviceName: '',
    servicePrice: '',
    barberName: '',
    barberPin: '',
    barberRole: 'admin'
  };

  function render() {
    container.innerHTML = `
      <div class="onboarding-page">
        <div class="onboarding-header">
          <h1>Selamat Datang di Pangkas 💈</h1>
          <p>Atur toko kamu dalam 3 langkah mudah</p>
          <div class="step-dots">
            <span class="step-dot ${step >= 1 ? 'active' : ''}">1</span>
            <span class="step-dot ${step >= 2 ? 'active' : ''}">2</span>
            <span class="step-dot ${step >= 3 ? 'active' : ''}">3</span>
          </div>
        </div>

        <div class="onboarding-body">
          ${step === 1 ? renderStep1() : ''}
          ${step === 2 ? renderStep2() : ''}
          ${step === 3 ? renderStep3() : ''}
        </div>

        <div class="onboarding-actions">
          ${step > 1 ? '<button class="btn btn-secondary" id="ob-back">← Kembali</button>' : '<div></div>'}
          ${step < 3 ? `<button class="btn btn-primary" id="ob-next">Lanjut →</button>` : ''}
          ${step === 3 ? `<button class="btn btn-primary" id="ob-finish">Mulai Pangkas! 🚀</button>` : ''}
        </div>
      </div>
    `;

    bindEvents();
  }

  function renderStep1() {
    return `
      <div class="onboarding-step">
        <h2>📍 Info Toko</h2>
        <div class="form-group">
          <label>Nama Toko *</label>
          <input type="text" id="ob-shop-name" class="input" placeholder="Contoh: Rome Bois Barbershop" value="${data.shopName}">
        </div>
        <div class="form-group">
          <label>Alamat</label>
          <input type="text" id="ob-shop-address" class="input" placeholder="Jl. Raya No. 1, Balikpapan" value="${data.shopAddress}">
        </div>
        <div class="form-group">
          <label>No HP / WhatsApp</label>
          <input type="tel" id="ob-shop-phone" class="input" placeholder="08xx-xxxx-xxxx" value="${data.shopPhone}">
        </div>
      </div>
    `;
  }

  function renderStep2() {
    return `
      <div class="onboarding-step">
        <h2>✂️ Layanan Pertama</h2>
        <p class="text-muted">Bisa ditambah lagi nanti di pengaturan</p>
        <div class="form-group">
          <label>Nama Layanan</label>
          <input type="text" id="ob-svc-name" class="input" placeholder="Contoh: Potong Rambut" value="${data.serviceName}">
        </div>
        <div class="form-group">
          <label>Harga (Rp)</label>
          <input type="number" id="ob-svc-price" class="input" placeholder="30000" value="${data.servicePrice}">
        </div>
        <button class="btn btn-outline btn-sm" id="ob-skip-svc">Pakai default (Potong Rambut Rp 30.000)</button>
      </div>
    `;
  }

  function renderStep3() {
    return `
      <div class="onboarding-step">
        <h2>💈 Barber Pertama</h2>
        <p class="text-muted">Ini juga jadi akun admin utama</p>
        <div class="form-group">
          <label>Nama Barber *</label>
          <input type="text" id="ob-barber-name" class="input" placeholder="Nama kamu" value="${data.barberName}">
        </div>
        <div class="form-group">
          <label>PIN (4 digit) *</label>
          <input type="number" id="ob-barber-pin" class="input" placeholder="1234" maxlength="4" value="${data.barberPin}">
        </div>
        <div class="form-group">
          <label>Role</label>
          <select id="ob-barber-role" class="input">
            <option value="admin" ${data.barberRole === 'admin' ? 'selected' : ''}>Admin</option>
            <option value="barber" ${data.barberRole === 'barber' ? 'selected' : ''}>Barber</option>
          </select>
        </div>
      </div>
    `;
  }

  function saveStepData() {
    if (step === 1) {
      data.shopName = (document.getElementById('ob-shop-name') || {}).value || '';
      data.shopAddress = (document.getElementById('ob-shop-address') || {}).value || '';
      data.shopPhone = (document.getElementById('ob-shop-phone') || {}).value || '';
    } else if (step === 2) {
      data.serviceName = (document.getElementById('ob-svc-name') || {}).value || '';
      data.servicePrice = (document.getElementById('ob-svc-price') || {}).value || '';
    } else if (step === 3) {
      data.barberName = (document.getElementById('ob-barber-name') || {}).value || '';
      data.barberPin = (document.getElementById('ob-barber-pin') || {}).value || '';
      data.barberRole = (document.getElementById('ob-barber-role') || {}).value || 'admin';
    }
  }

  function bindEvents() {
    const backBtn = document.getElementById('ob-back');
    const nextBtn = document.getElementById('ob-next');
    const finishBtn = document.getElementById('ob-finish');
    const skipBtn = document.getElementById('ob-skip-svc');

    if (backBtn) backBtn.addEventListener('click', () => {
      saveStepData();
      step--;
      render();
    });

    if (nextBtn) nextBtn.addEventListener('click', () => {
      saveStepData();
      if (step === 1 && !data.shopName.trim()) {
        UI.toast('Nama toko wajib diisi!', 'error');
        return;
      }
      step++;
      render();
    });

    if (skipBtn) skipBtn.addEventListener('click', () => {
      data.serviceName = 'Potong Rambut';
      data.servicePrice = '30000';
      step++;
      render();
    });

    if (finishBtn) finishBtn.addEventListener('click', () => {
      saveStepData();
      if (!data.barberName.trim()) {
        UI.toast('Nama barber wajib diisi!', 'error');
        return;
      }
      if (!data.barberPin || data.barberPin.length !== 4) {
        UI.toast('PIN harus 4 digit!', 'error');
        return;
      }
      finishOnboarding();
    });
  }

  function finishOnboarding() {
    // Save settings
    const settings = DB.get('settings') || {};
    settings.shop = {
      name: data.shopName,
      address: data.shopAddress,
      phone: data.shopPhone,
      logo: null,
      tagline: ''
    };
    settings.commission = settings.commission || 40;
    settings.memberVisits = settings.memberVisits || 10;
    settings.memberReward = settings.memberReward || '1x Potong Gratis';
    settings.sessionTimeout = settings.sessionTimeout || 15;
    settings.queueEstimate = settings.queueEstimate || 20;
    DB.set('settings', settings);

    // Save service
    const services = DB.get('services') || [];
    if (data.serviceName.trim()) {
      services.push({
        id: generateId('svc'),
        name: data.serviceName.trim(),
        price: parseInt(data.servicePrice) || 30000,
        active: true
      });
    }
    if (services.length === 0) {
      services.push({
        id: generateId('svc'),
        name: 'Potong Rambut',
        price: 30000,
        active: true
      });
    }
    DB.set('services', services);

    // Save barber
    const barbers = DB.get('barbers') || [];
    const newBarber = {
      id: generateId('brb'),
      name: data.barberName.trim(),
      pin: data.barberPin,
      role: data.barberRole,
      active: true
    };
    barbers.push(newBarber);
    DB.set('barbers', barbers);

    // Set current user
    currentUser = newBarber;
    DB.set('currentUser', newBarber);

    UI.toast('Toko berhasil diatur! 🎉', 'success');
    navigateTo('home');
  }

  render();
}

// home.js — Dashboard
function renderHome(container) {
  const today = new Date().toISOString().slice(0, 10);
  const transactions = DB.get('transactions') || [];
  const queue = DB.get('queue') || [];
  const members = DB.get('members') || [];
  const appointments = DB.get('appointments') || [];
  const barbers = DB.get('barbers') || [];
  const settings = DB.get('settings') || {};
  const shopName = (settings.shop && settings.shop.name) || 'Pangkas';

  // Today's stats
  const todayTx = transactions.filter(t => t.date && t.date.startsWith(today));
  const todayRevenue = todayTx.reduce((sum, t) => sum + (t.total || 0), 0);
  const activeQueue = queue.filter(q => q.date === today && (q.status === 'menunggu' || q.status === 'dilayani'));
  const memberCount = members.length;

  // Next appointment
  const now = new Date();
  const upcoming = appointments
    .filter(a => a.status !== 'batal' && a.status !== 'selesai')
    .filter(a => {
      const dt = new Date(a.date + 'T' + (a.time || '00:00'));
      return dt >= now;
    })
    .sort((a, b) => {
      const da = new Date(a.date + 'T' + (a.time || '00:00'));
      const db = new Date(b.date + 'T' + (b.time || '00:00'));
      return da - db;
    });
  const nextAppt = upcoming[0] || null;

  // Barbers on duty (barbers who have transactions today or are active)
  const activeBarbers = barbers.filter(b => b.active !== false);

  // Recent transactions (last 5)
  const recent = transactions.slice(-5).reverse();

  container.innerHTML = `
    <div class="page-home">
      <div class="home-greeting">
        <h1>Halo, ${currentUser ? currentUser.name : 'Boss'}! 👋</h1>
        <p class="text-muted">${shopName} — ${formatDateIndo(today)}</p>
      </div>

      <div class="stat-cards">
        <div class="stat-card stat-revenue">
          <div class="stat-icon">💰</div>
          <div class="stat-value">${rp(todayRevenue)}</div>
          <div class="stat-label">Pendapatan Hari Ini</div>
        </div>
        <div class="stat-card stat-tx">
          <div class="stat-icon">🧾</div>
          <div class="stat-value">${todayTx.length}</div>
          <div class="stat-label">Transaksi</div>
        </div>
        <div class="stat-card stat-queue">
          <div class="stat-icon">📋</div>
          <div class="stat-value">${activeQueue.length}</div>
          <div class="stat-label">Antrian Aktif</div>
        </div>
        <div class="stat-card stat-member">
          <div class="stat-icon">👥</div>
          <div class="stat-value">${memberCount}</div>
          <div class="stat-label">Member</div>
        </div>
      </div>

      ${nextAppt ? `
        <div class="card next-appt-card">
          <h3>📅 Janji Berikutnya</h3>
          <div class="appt-preview">
            <strong>${nextAppt.name}</strong>
            <span>${nextAppt.date} ${nextAppt.time || ''}</span>
            <span class="badge">${nextAppt.service || ''}</span>
          </div>
        </div>
      ` : ''}

      <div class="quick-actions">
        <button class="btn btn-primary btn-lg" onclick="navigateTo('kasir')">
          💰 Transaksi Baru
        </button>
        <button class="btn btn-secondary btn-lg" onclick="navigateTo('antrian')">
          📋 Tambah Antrian
        </button>
        <button class="btn btn-outline btn-lg" onclick="navigateTo('janji')">
          📅 Buat Janji
        </button>
      </div>

      ${activeBarbers.length > 0 ? `
        <div class="card">
          <h3>💈 Barber On Duty</h3>
          <div class="barber-chips">
            ${activeBarbers.map(b => `
              <span class="chip barber-chip">
                <span class="chip-dot"></span>
                ${b.name}
                <span class="badge badge-sm">${b.role || 'barber'}</span>
              </span>
            `).join('')}
          </div>
        </div>
      ` : ''}

      ${recent.length > 0 ? `
        <div class="card">
          <h3>🧾 Transaksi Terakhir</h3>
          <div class="tx-list">
            ${recent.map(t => `
              <div class="tx-item">
                <div class="tx-info">
                  <strong>${t.customerName || 'Walk-in'}</strong>
                  <span class="text-muted">${t.barberName || ''} • ${t.paymentMethod || 'cash'}</span>
                </div>
                <div class="tx-amount">${rp(t.total || 0)}</div>
              </div>
            `).join('')}
          </div>
        </div>
      ` : `
        <div class="card empty-state">
          <p>Belum ada transaksi hari ini. Yuk mulai! 🚀</p>
        </div>
      `}
    </div>
  `;
}

function formatDateIndo(dateStr) {
  const days = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];
  const months = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];
  const d = new Date(dateStr + 'T00:00:00');
  return `${days[d.getDay()]}, ${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
}

// kasir.js — POS / Cashier
function renderKasir(container) {
  const services = (DB.get('services') || []).filter(s => s.active !== false);
  const addons = (DB.get('addons') || []).filter(a => a.active !== false);
  const barbers = (DB.get('barbers') || []).filter(b => b.active !== false);
  const members = DB.get('members') || [];
  const settings = DB.get('settings') || {};

  let cart = [];
  let selectedBarber = barbers.length > 0 ? barbers[0].id : '';
  let customerName = '';
  let selectedMember = null;
  let discountPct = 0;
  let customDiscount = 0;

  // Check if coming from queue with pre-filled data
  const prefill = window._kasirPrefill || null;
  if (prefill) {
    customerName = prefill.customerName || '';
    selectedBarber = prefill.barberId || selectedBarber;
    if (prefill.serviceId) {
      const svc = services.find(s => s.id === prefill.serviceId);
      if (svc) cart.push({ id: svc.id, name: svc.name, price: svc.price, qty: 1, type: 'service' });
    }
    window._kasirPrefill = null;
  }

  function getTotal() {
    const subtotal = cart.reduce((s, item) => s + (item.price * item.qty), 0);
    const disc = discountPct > 0 ? Math.round(subtotal * discountPct / 100) : customDiscount;
    return Math.max(0, subtotal - disc);
  }

  function getSubtotal() {
    return cart.reduce((s, item) => s + (item.price * item.qty), 0);
  }

  function getDiscount() {
    const subtotal = getSubtotal();
    return discountPct > 0 ? Math.round(subtotal * discountPct / 100) : customDiscount;
  }

  function render() {
    const barber = barbers.find(b => b.id === selectedBarber);
    const barberName = barber ? barber.name : '';

    container.innerHTML = `
      <div class="page-kasir">
        <div class="kasir-header">
          <h2>💰 Kasir</h2>
        </div>

        <div class="kasir-services">
          <h3>Layanan</h3>
          <div class="service-grid" id="svc-grid">
            ${services.map(s => `
              <button class="svc-btn" data-id="${s.id}" data-name="${s.name}" data-price="${s.price}" data-type="service">
                <span class="svc-name">${s.name}</span>
                <span class="svc-price">${rp(s.price)}</span>
              </button>
            `).join('')}
          </div>
        </div>

        ${addons.length > 0 ? `
          <div class="kasir-addons">
            <h3>Add-on / Produk</h3>
            <div class="service-grid" id="addon-grid">
              ${addons.map(a => `
                <button class="svc-btn addon-btn ${(a.stock || 0) <= 0 ? 'out-of-stock' : ''}" 
                  data-id="${a.id}" data-name="${a.name}" data-price="${a.price}" data-type="addon"
                  ${(a.stock || 0) <= 0 ? 'disabled' : ''}>
                  <span class="svc-name">${a.name}</span>
                  <span class="svc-price">${rp(a.price)}</span>
                  <span class="svc-stock">Stok: ${a.stock || 0}</span>
                </button>
              `).join('')}
            </div>
          </div>
        ` : ''}

        <div class="kasir-cart" id="kasir-cart">
          <h3>🛒 Keranjang</h3>

          <div class="cart-customer">
            <div class="form-group">
              <label>Nama Customer</label>
              <input type="text" id="customer-name" class="input" placeholder="Nama / cari member..." value="${customerName}" autocomplete="off">
              <div class="autocomplete-list" id="member-autocomplete" style="display:none;"></div>
            </div>
            <div class="form-group">
              <label>Barber</label>
              <select id="barber-select" class="input">
                ${barbers.map(b => `<option value="${b.id}" ${b.id === selectedBarber ? 'selected' : ''}>${b.name}</option>`).join('')}
              </select>
            </div>
            ${selectedMember ? `
              <button class="btn btn-outline btn-sm" id="btn-seperti-biasa">🔄 Seperti Biasa</button>
            ` : ''}
          </div>

          ${cart.length > 0 ? `
            <div class="cart-items">
              ${cart.map((item, idx) => `
                <div class="cart-item">
                  <div class="cart-item-info">
                    <span class="cart-item-name">${item.name}</span>
                    <span class="cart-item-price">${rp(item.price)}</span>
                  </div>
                  <div class="cart-item-actions">
                    <button class="btn-qty" data-action="minus" data-idx="${idx}">−</button>
                    <span class="cart-item-qty">${item.qty}</span>
                    <button class="btn-qty" data-action="plus" data-idx="${idx}">+</button>
                    <button class="btn-remove" data-idx="${idx}">✕</button>
                  </div>
                </div>
              `).join('')}
            </div>

            <div class="discount-section">
              <label>Diskon</label>
              <div class="discount-chips">
                <button class="chip ${discountPct === 0 && customDiscount === 0 ? 'active' : ''}" data-disc="0">Tanpa</button>
                <button class="chip ${discountPct === 10 ? 'active' : ''}" data-disc="10">10%</button>
                <button class="chip ${discountPct === 20 ? 'active' : ''}" data-disc="20">20%</button>
                <button class="chip ${discountPct === 50 ? 'active' : ''}" data-disc="50">50%</button>
                <button class="chip ${discountPct === -1 ? 'active' : ''}" data-disc="custom">Custom</button>
              </div>
            </div>

            <div class="cart-summary">
              <div class="cart-line"><span>Subtotal</span><span>${rp(getSubtotal())}</span></div>
              ${getDiscount() > 0 ? `<div class="cart-line discount-line"><span>Diskon</span><span>-${rp(getDiscount())}</span></div>` : ''}
              <div class="cart-line cart-total"><span>Total</span><span>${rp(getTotal())}</span></div>
            </div>

            <button class="btn btn-primary btn-lg btn-block" id="btn-bayar">Bayar ${rp(getTotal())}</button>
          ` : `
            <div class="empty-cart">
              <p>Ketuk layanan untuk menambahkan ke keranjang</p>
            </div>
          `}
        </div>
      </div>
    `;

    bindEvents();
  }

  function bindEvents() {
    // Service grid click
    container.querySelectorAll('.svc-btn').forEach(btn => {
      btn.addEventListener('click', function() {
        const id = this.dataset.id;
        const name = this.dataset.name;
        const price = parseInt(this.dataset.price);
        const type = this.dataset.type;
        addToCart(id, name, price, type);
      });
    });

    // Cart qty buttons
    container.querySelectorAll('.btn-qty').forEach(btn => {
      btn.addEventListener('click', function() {
        const idx = parseInt(this.dataset.idx);
        const action = this.dataset.action;
        if (action === 'plus') cart[idx].qty++;
        else if (action === 'minus') {
          cart[idx].qty--;
          if (cart[idx].qty <= 0) cart.splice(idx, 1);
        }
        render();
      });
    });

    // Cart remove buttons
    container.querySelectorAll('.btn-remove').forEach(btn => {
      btn.addEventListener('click', function() {
        const idx = parseInt(this.dataset.idx);
        cart.splice(idx, 1);
        render();
      });
    });

    // Customer name autocomplete
    const nameInput = document.getElementById('customer-name');
    if (nameInput) {
      nameInput.addEventListener('input', function() {
        customerName = this.value;
        const q = this.value.toLowerCase().trim();
        const acList = document.getElementById('member-autocomplete');
        if (q.length < 2) {
          acList.style.display = 'none';
          selectedMember = null;
          return;
        }
        const matches = members.filter(m =>
          m.name.toLowerCase().includes(q) || (m.phone && m.phone.includes(q))
        ).slice(0, 5);
        if (matches.length > 0) {
          acList.innerHTML = matches.map(m => `
            <div class="ac-item" data-id="${m.id}" data-name="${m.name}">
              ${m.name} <span class="text-muted">${m.phone || ''}</span>
            </div>
          `).join('');
          acList.style.display = 'block';
          acList.querySelectorAll('.ac-item').forEach(item => {
            item.addEventListener('click', function() {
              const mid = this.dataset.id;
              const mname = this.dataset.name;
              selectedMember = members.find(m => m.id === mid) || null;
              customerName = mname;
              nameInput.value = mname;
              acList.style.display = 'none';
              render();
            });
          });
        } else {
          acList.style.display = 'none';
        }
      });
    }

    // Barber select
    const barberSel = document.getElementById('barber-select');
    if (barberSel) {
      barberSel.addEventListener('change', function() {
        selectedBarber = this.value;
      });
    }

    // Seperti Biasa
    const sbBtn = document.getElementById('btn-seperti-biasa');
    if (sbBtn) {
      sbBtn.addEventListener('click', function() {
        if (!selectedMember) return;
        const allTx = DB.get('transactions') || [];
        const memberTx = allTx.filter(t => t.memberId === selectedMember.id).sort((a, b) => b.timestamp - a.timestamp);
        if (memberTx.length > 0) {
          const lastTx = memberTx[0];
          cart = (lastTx.items || []).map(item => ({
            id: item.id,
            name: item.name,
            price: item.price,
            qty: item.qty || 1,
            type: item.type || 'service'
          }));
          if (lastTx.barberId) selectedBarber = lastTx.barberId;
          UI.toast('Order terakhir dimuat! 🔄', 'success');
          render();
        } else {
          UI.toast('Belum ada riwayat transaksi', 'info');
        }
      });
    }

    // Discount chips
    container.querySelectorAll('.discount-chips .chip').forEach(chip => {
      chip.addEventListener('click', function() {
        const disc = this.dataset.disc;
        if (disc === 'custom') {
          discountPct = -1;
          const val = prompt('Masukkan jumlah diskon (Rp):');
          if (val && !isNaN(val)) {
            customDiscount = parseInt(val);
            discountPct = 0;
          } else {
            discountPct = 0;
            customDiscount = 0;
          }
        } else {
          discountPct = parseInt(disc);
          customDiscount = 0;
        }
        render();
      });
    });

    // Bayar button
    const bayarBtn = document.getElementById('btn-bayar');
    if (bayarBtn) {
      bayarBtn.addEventListener('click', showPaymentModal);
    }
  }

  function addToCart(id, name, price, type) {
    const existing = cart.find(c => c.id === id);
    if (existing) {
      // For addons, check stock
      if (type === 'addon') {
        const addon = addons.find(a => a.id === id);
        if (addon && existing.qty >= (addon.stock || 0)) {
          UI.toast('Stok tidak cukup!', 'error');
          return;
        }
      }
      existing.qty++;
    } else {
      cart.push({ id, name, price, qty: 1, type });
    }
    render();
  }

  function showPaymentModal() {
    const total = getTotal();
    const html = `
      <div class="payment-modal">
        <h2>Pembayaran</h2>
        <div class="payment-total">${rp(total)}</div>

        <div class="payment-methods">
          <button class="payment-method-btn" data-method="cash">
            💵 Cash
          </button>
          <button class="payment-method-btn" data-method="transfer">
            🏦 Transfer
          </button>
          <button class="payment-method-btn" data-method="qris">
            📱 QRIS
          </button>
          <button class="payment-method-btn" data-method="hutang">
            📝 Hutang
          </button>
        </div>

        <div id="hutang-note" style="display:none;" class="form-group">
          <label>Catatan Hutang</label>
          <input type="text" id="hutang-note-input" class="input" placeholder="Catatan...">
        </div>

        <div class="payment-actions">
          <button class="btn btn-secondary" id="pay-cancel">Batal</button>
          <button class="btn btn-primary" id="pay-confirm" disabled>Konfirmasi</button>
        </div>
      </div>
    `;

    UI.showModal(html);

    let selectedMethod = '';

    document.querySelectorAll('.payment-method-btn').forEach(btn => {
      btn.addEventListener('click', function() {
        document.querySelectorAll('.payment-method-btn').forEach(b => b.classList.remove('active'));
        this.classList.add('active');
        selectedMethod = this.dataset.method;
        document.getElementById('pay-confirm').disabled = false;
        document.getElementById('hutang-note').style.display = selectedMethod === 'hutang' ? 'block' : 'none';
      });
    });

    document.getElementById('pay-cancel').addEventListener('click', () => UI.closeModal());

    document.getElementById('pay-confirm').addEventListener('click', () => {
      if (!selectedMethod) return;
      const hutangNote = selectedMethod === 'hutang' ?
        (document.getElementById('hutang-note-input') || {}).value || '' : '';
      processPayment(selectedMethod, hutangNote);
    });
  }

  function processPayment(method, hutangNote) {
    const barber = barbers.find(b => b.id === selectedBarber);
    const commission = settings.commission || 40;
    const total = getTotal();
    const commissionAmount = Math.round(total * commission / 100);

    const tx = {
      id: generateId('tx'),
      date: new Date().toISOString().slice(0, 10),
      time: new Date().toTimeString().slice(0, 5),
      timestamp: Date.now(),
      customerName: customerName || 'Walk-in',
      memberId: selectedMember ? selectedMember.id : null,
      barberId: selectedBarber,
      barberName: barber ? barber.name : '',
      items: cart.map(c => ({ id: c.id, name: c.name, price: c.price, qty: c.qty, type: c.type })),
      subtotal: getSubtotal(),
      discount: getDiscount(),
      discountPct: discountPct > 0 ? discountPct : 0,
      total: total,
      commission: commissionAmount,
      paymentMethod: method,
      hutangNote: hutangNote,
      paid: method !== 'hutang'
    };

    // Save transaction
    const transactions = DB.get('transactions') || [];
    transactions.push(tx);
    DB.set('transactions', transactions);

    // Update addon stock
    cart.forEach(item => {
      if (item.type === 'addon') {
        const allAddons = DB.get('addons') || [];
        const addon = allAddons.find(a => a.id === item.id);
        if (addon) {
          addon.stock = Math.max(0, (addon.stock || 0) - item.qty);
          DB.set('addons', allAddons);
        }
      }
    });

    // Update member visits
    if (selectedMember) {
      const allMembers = DB.get('members') || [];
      const mem = allMembers.find(m => m.id === selectedMember.id);
      if (mem) {
        mem.visits = (mem.visits || 0) + 1;
        mem.lastVisit = new Date().toISOString().slice(0, 10);
        mem.totalSpent = (mem.totalSpent || 0) + total;
        DB.set('members', allMembers);
      }
    }

    UI.closeModal();

    // Show receipt option
    showReceiptModal(tx);
  }

  function showReceiptModal(tx) {
    const shop = (settings.shop || {});
    const html = `
      <div class="receipt-modal">
        <h2>✅ Transaksi Berhasil!</h2>
        <div class="receipt" id="receipt-content">
          <div class="receipt-header">
            <strong>${shop.name || 'Pangkas'}</strong><br>
            ${shop.address || ''}<br>
            ${shop.phone || ''}
          </div>
          <div class="receipt-divider">================================</div>
          <div class="receipt-date">${tx.date} ${tx.time}</div>
          <div class="receipt-barber">Barber: ${tx.barberName}</div>
          <div class="receipt-customer">Customer: ${tx.customerName}</div>
          <div class="receipt-divider">--------------------------------</div>
          ${tx.items.map(item => `
            <div class="receipt-item">
              <span>${item.name} x${item.qty}</span>
              <span>${rp(item.price * item.qty)}</span>
            </div>
          `).join('')}
          <div class="receipt-divider">--------------------------------</div>
          ${tx.discount > 0 ? `
            <div class="receipt-item"><span>Subtotal</span><span>${rp(tx.subtotal)}</span></div>
            <div class="receipt-item"><span>Diskon</span><span>-${rp(tx.discount)}</span></div>
          ` : ''}
          <div class="receipt-item receipt-total">
            <span><strong>TOTAL</strong></span>
            <span><strong>${rp(tx.total)}</strong></span>
          </div>
          <div class="receipt-payment">Bayar: ${tx.paymentMethod.toUpperCase()}</div>
          ${tx.paymentMethod === 'hutang' ? `<div class="receipt-hutang">⚠️ HUTANG${tx.hutangNote ? ': ' + tx.hutangNote : ''}</div>` : ''}
          <div class="receipt-divider">================================</div>
          <div class="receipt-footer">Terima kasih! 💈</div>
        </div>
        <div class="receipt-actions">
          <button class="btn btn-outline" id="btn-print-struk">🖨️ Print Struk</button>
          <button class="btn btn-primary" id="btn-done-tx">Selesai</button>
        </div>
      </div>
    `;

    UI.showModal(html);

    document.getElementById('btn-print-struk').addEventListener('click', () => {
      const content = document.getElementById('receipt-content');
      const win = window.open('', '_blank', 'width=300,height=600');
      win.document.write(`<html><head><title>Struk</title><style>
        body{font-family:monospace;font-size:12px;width:280px;margin:0 auto;padding:10px;}
        .receipt-item{display:flex;justify-content:space-between;}
        .receipt-header{text-align:center;margin-bottom:10px;}
        .receipt-footer{text-align:center;margin-top:10px;}
        .receipt-divider{text-align:center;color:#999;}
      </style></head><body>${content.innerHTML}</body></html>`);
      win.document.close();
      win.print();
    });

    document.getElementById('btn-done-tx').addEventListener('click', () => {
      UI.closeModal();
      cart = [];
      customerName = '';
      selectedMember = null;
      discountPct = 0;
      customDiscount = 0;
      render();
      UI.toast('Transaksi selesai! 🎉', 'success');
    });
  }

  render();
}

// antrian.js — Queue Management
function renderAntrian(container) {
  const today = new Date().toISOString().slice(0, 10);
  const services = (DB.get('services') || []).filter(s => s.active !== false);
  const barbers = (DB.get('barbers') || []).filter(b => b.active !== false);
  const settings = DB.get('settings') || {};
  const estimateMin = settings.queueEstimate || 20;

  // Auto-reset: clear completed items from previous days
  let queue = DB.get('queue') || [];
  const prevDayCompleted = queue.filter(q => q.date !== today && (q.status === 'selesai' || q.status === 'batal'));
  if (prevDayCompleted.length > 0) {
    queue = queue.filter(q => !(q.date !== today && (q.status === 'selesai' || q.status === 'batal')));
    DB.set('queue', queue);
  }

  // Today's queue
  const todayQueue = queue.filter(q => q.date === today);
  const activeQueue = todayQueue.filter(q => q.status === 'menunggu' || q.status === 'dilayani');
  const completedQueue = todayQueue.filter(q => q.status === 'selesai' || q.status === 'batal');

  // Next queue number for today
  const maxNum = todayQueue.reduce((max, q) => Math.max(max, q.number || 0), 0);

  function render() {
    const q = DB.get('queue') || [];
    const tq = q.filter(qi => qi.date === today);
    const active = tq.filter(qi => qi.status === 'menunggu' || qi.status === 'dilayani');
    const completed = tq.filter(qi => qi.status === 'selesai' || qi.status === 'batal');
    const currentMax = tq.reduce((max, qi) => Math.max(max, qi.number || 0), 0);

    container.innerHTML = `
      <div class="page-antrian">
        <div class="page-header">
          <h2>📋 Antrian</h2>
          <button class="btn btn-primary" id="btn-add-queue">+ Tambah</button>
        </div>

        ${active.length === 0 ? `
          <div class="empty-state card">
            <p>Belum ada antrian. Tap "Tambah" untuk menambahkan. 📋</p>
          </div>
        ` : ''}

        <div class="queue-list">
          ${active.sort((a, b) => a.number - b.number).map((item, idx) => {
            const waitPos = active.filter(a => a.status === 'menunggu').indexOf(item);
            const estWait = item.status === 'menunggu' ? (waitPos >= 0 ? (waitPos) * estimateMin : 0) : 0;
            return `
              <div class="queue-card ${item.status === 'dilayani' ? 'queue-serving' : ''}">
                <div class="queue-number">${String(item.number).padStart(2, '0')}</div>
                <div class="queue-info">
                  <strong>${item.customerName || 'Walk-in'}</strong>
                  <span class="text-muted">${item.serviceName || ''}</span>
                  <span class="text-muted">Barber: ${item.barberName || 'Auto'}</span>
                  ${item.status === 'menunggu' && estWait > 0 ? `<span class="queue-wait">⏱️ ~${estWait} menit</span>` : ''}
                </div>
                <div class="queue-status">
                  <span class="badge badge-${item.status === 'dilayani' ? 'success' : 'warning'}">
                    ${item.status === 'menunggu' ? 'Menunggu' : 'Dilayani'}
                  </span>
                </div>
                <div class="queue-actions">
                  ${item.status === 'menunggu' ? `
                    <button class="btn btn-sm btn-primary" data-action="mulai" data-id="${item.id}">▶ Mulai</button>
                  ` : ''}
                  ${item.status === 'dilayani' ? `
                    <button class="btn btn-sm btn-success" data-action="selesai" data-id="${item.id}">✅ Selesai</button>
                  ` : ''}
                  <button class="btn btn-sm btn-danger" data-action="batal" data-id="${item.id}">✕</button>
                </div>
              </div>
            `;
          }).join('')}
        </div>

        ${completed.length > 0 ? `
          <div class="card" style="margin-top:1rem;">
            <h3>Riwayat Hari Ini</h3>
            <div class="completed-queue">
              ${completed.map(item => `
                <div class="queue-completed-item">
                  <span class="queue-number-sm">${String(item.number).padStart(2, '0')}</span>
                  <span>${item.customerName || 'Walk-in'} — ${item.serviceName || ''}</span>
                  <span class="badge badge-${item.status === 'selesai' ? 'success' : 'danger'}">
                    ${item.status === 'selesai' ? 'Selesai' : 'Batal'}
                  </span>
                </div>
              `).join('')}
            </div>
          </div>
        ` : ''}
      </div>
    `;

    bindEvents();
  }

  function bindEvents() {
    // Add queue button
    document.getElementById('btn-add-queue').addEventListener('click', showAddQueueModal);

    // Queue action buttons
    container.querySelectorAll('[data-action]').forEach(btn => {
      btn.addEventListener('click', function() {
        const action = this.dataset.action;
        const id = this.dataset.id;
        handleQueueAction(action, id);
      });
    });
  }

  function showAddQueueModal() {
    const html = `
      <div class="add-queue-modal">
        <h2>Tambah Antrian</h2>
        <div class="form-group">
          <label>Nama Customer</label>
          <input type="text" id="q-name" class="input" placeholder="Nama...">
        </div>
        <div class="form-group">
          <label>Layanan</label>
          <select id="q-service" class="input">
            ${services.map(s => `<option value="${s.id}" data-name="${s.name}">${s.name} — ${rp(s.price)}</option>`).join('')}
          </select>
        </div>
        <div class="form-group">
          <label>Barber</label>
          <select id="q-barber" class="input">
            <option value="">Auto-assign</option>
            ${barbers.map(b => `<option value="${b.id}" data-name="${b.name}">${b.name}</option>`).join('')}
          </select>
        </div>
        <div class="modal-actions">
          <button class="btn btn-secondary" id="q-cancel">Batal</button>
          <button class="btn btn-primary" id="q-save">Tambah</button>
        </div>
      </div>
    `;

    UI.showModal(html);

    document.getElementById('q-cancel').addEventListener('click', () => UI.closeModal());
    document.getElementById('q-save').addEventListener('click', () => {
      const name = document.getElementById('q-name').value.trim();
      const serviceSelect = document.getElementById('q-service');
      const serviceId = serviceSelect.value;
      const serviceName = serviceSelect.options[serviceSelect.selectedIndex].dataset.name || '';
      const barberSelect = document.getElementById('q-barber');
      const barberId = barberSelect.value;
      const barberName = barberId ? (barberSelect.options[barberSelect.selectedIndex].dataset.name || '') : autoAssignBarber();

      // Get current queue for numbering
      const allQueue = DB.get('queue') || [];
      const todayItems = allQueue.filter(qi => qi.date === today);
      const nextNum = todayItems.reduce((max, qi) => Math.max(max, qi.number || 0), 0) + 1;

      const newItem = {
        id: generateId('q'),
        date: today,
        number: nextNum,
        customerName: name || 'Walk-in',
        serviceId: serviceId,
        serviceName: serviceName,
        barberId: barberId || '',
        barberName: barberName,
        status: 'menunggu',
        timestamp: Date.now()
      };

      allQueue.push(newItem);
      DB.set('queue', allQueue);
      UI.closeModal();
      UI.toast(`Antrian #${String(nextNum).padStart(2, '0')} ditambahkan!`, 'success');
      render();
    });
  }

  function autoAssignBarber() {
    // Find barber with least active queue items
    const allQueue = DB.get('queue') || [];
    const activeItems = allQueue.filter(q => q.date === today && (q.status === 'menunggu' || q.status === 'dilayani'));

    let minCount = Infinity;
    let assignedBarber = barbers[0] || null;

    barbers.forEach(b => {
      const count = activeItems.filter(q => q.barberId === b.id).length;
      if (count < minCount) {
        minCount = count;
        assignedBarber = b;
      }
    });

    return assignedBarber ? assignedBarber.name : '';
  }

  function handleQueueAction(action, id) {
    const allQueue = DB.get('queue') || [];
    const item = allQueue.find(q => q.id === id);
    if (!item) return;

    if (action === 'mulai') {
      item.status = 'dilayani';
      item.startTime = Date.now();
      DB.set('queue', allQueue);
      UI.toast(`Melayani ${item.customerName}...`, 'info');
      render();
    } else if (action === 'selesai') {
      item.status = 'selesai';
      item.endTime = Date.now();
      DB.set('queue', allQueue);
      UI.toast(`${item.customerName} selesai! ✅`, 'success');

      // Ask if want to go to Kasir
      UI.showModal(`
        <div class="confirm-modal">
          <h3>Lanjut ke Kasir?</h3>
          <p>Buat transaksi untuk ${item.customerName}?</p>
          <div class="modal-actions">
            <button class="btn btn-secondary" id="q-skip-kasir">Tidak</button>
            <button class="btn btn-primary" id="q-goto-kasir">Ya, ke Kasir</button>
          </div>
        </div>
      `);

      document.getElementById('q-skip-kasir').addEventListener('click', () => {
        UI.closeModal();
        render();
      });
      document.getElementById('q-goto-kasir').addEventListener('click', () => {
        UI.closeModal();
        window._kasirPrefill = {
          customerName: item.customerName,
          barberId: item.barberId,
          serviceId: item.serviceId
        };
        navigateTo('kasir');
      });
    } else if (action === 'batal') {
      item.status = 'batal';
      DB.set('queue', allQueue);
      UI.toast('Antrian dibatalkan', 'info');
      render();
    }
  }

  render();
}

// janji.js — Appointments
function renderJanji(container) {
  const appointments = DB.get('appointments') || [];
  const services = (DB.get('services') || []).filter(s => s.active !== false);
  const barbers = (DB.get('barbers') || []).filter(b => b.active !== false);
  const settings = DB.get('settings') || {};
  const shopName = (settings.shop && settings.shop.name) || 'Pangkas';

  const now = new Date();
  let viewYear = now.getFullYear();
  let viewMonth = now.getMonth();
  let selectedDate = now.toISOString().slice(0, 10);

  function render() {
    const daysInMonth = new Date(viewYear, viewMonth + 1, 0).getDate();
    const firstDay = new Date(viewYear, viewMonth, 1).getDay();
    const months = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];

    // Find days with appointments
    const apptDates = {};
    appointments.forEach(a => {
      if (a.date && a.date.startsWith(`${viewYear}-${String(viewMonth + 1).padStart(2, '0')}`)) {
        apptDates[a.date] = (apptDates[a.date] || 0) + 1;
      }
    });

    // Calendar grid
    let calendarHTML = '';
    const dayNames = ['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'];

    calendarHTML += '<div class="cal-header-row">';
    dayNames.forEach(d => { calendarHTML += `<div class="cal-day-name">${d}</div>`; });
    calendarHTML += '</div>';

    calendarHTML += '<div class="cal-grid">';
    // Empty cells before first day
    for (let i = 0; i < firstDay; i++) {
      calendarHTML += '<div class="cal-cell empty"></div>';
    }

    for (let d = 1; d <= daysInMonth; d++) {
      const dateStr = `${viewYear}-${String(viewMonth + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      const isToday = dateStr === now.toISOString().slice(0, 10);
      const isSelected = dateStr === selectedDate;
      const hasAppt = apptDates[dateStr] > 0;

      calendarHTML += `
        <div class="cal-cell ${isToday ? 'today' : ''} ${isSelected ? 'selected' : ''} ${hasAppt ? 'has-appt' : ''}" 
             data-date="${dateStr}">
          <span class="cal-date">${d}</span>
          ${hasAppt ? `<span class="cal-dot"></span>` : ''}
        </div>
      `;
    }
    calendarHTML += '</div>';

    // Selected date appointments
    const dayAppts = appointments
      .filter(a => a.date === selectedDate && a.status !== 'batal')
      .sort((a, b) => (a.time || '').localeCompare(b.time || ''));

    container.innerHTML = `
      <div class="page-janji">
        <div class="page-header">
          <h2>📅 Jadwal & Janji</h2>
          <button class="btn btn-primary" id="btn-add-appt">+ Buat Janji</button>
        </div>

        <div class="calendar-card card">
          <div class="cal-nav">
            <button class="btn btn-sm btn-outline" id="cal-prev">◀</button>
            <h3>${months[viewMonth]} ${viewYear}</h3>
            <button class="btn btn-sm btn-outline" id="cal-next">▶</button>
          </div>
          ${calendarHTML}
        </div>

        <div class="day-appointments">
          <h3>${formatDateIndo(selectedDate)}</h3>
          ${dayAppts.length === 0 ? `
            <div class="empty-state"><p>Tidak ada janji di tanggal ini</p></div>
          ` : ''}
          ${dayAppts.map(a => `
            <div class="appt-card card">
              <div class="appt-header">
                <span class="appt-time">${a.time || '--:--'}</span>
                <span class="badge badge-${getStatusColor(a.status)}">${getStatusLabel(a.status)}</span>
              </div>
              <div class="appt-body">
                <strong>${a.name}</strong>
                ${a.phone ? `<span class="text-muted">📱 ${a.phone}</span>` : ''}
                <span>${a.service || ''} ${a.barberName ? '— ' + a.barberName : ''}</span>
                ${a.notes ? `<span class="text-muted">📝 ${a.notes}</span>` : ''}
              </div>
              <div class="appt-actions">
                ${a.status === 'menunggu' ? `
                  <button class="btn btn-sm btn-primary" data-action="confirm" data-id="${a.id}">✅ Konfirmasi</button>
                ` : ''}
                ${a.status === 'dikonfirmasi' ? `
                  <button class="btn btn-sm btn-success" data-action="done" data-id="${a.id}">✅ Selesai</button>
                ` : ''}
                ${a.phone ? `
                  <button class="btn btn-sm btn-outline" data-action="wa-remind" data-id="${a.id}">📱 WA Reminder</button>
                ` : ''}
                <button class="btn btn-sm btn-danger" data-action="cancel" data-id="${a.id}">Batal</button>
                <button class="btn btn-sm btn-outline" data-action="delete" data-id="${a.id}">🗑️</button>
              </div>
            </div>
          `).join('')}
        </div>
      </div>
    `;

    bindEvents();
  }

  function getStatusColor(s) {
    switch (s) {
      case 'menunggu': return 'warning';
      case 'dikonfirmasi': return 'info';
      case 'selesai': return 'success';
      case 'batal': return 'danger';
      default: return 'default';
    }
  }

  function getStatusLabel(s) {
    switch (s) {
      case 'menunggu': return 'Menunggu';
      case 'dikonfirmasi': return 'Dikonfirmasi';
      case 'selesai': return 'Selesai';
      case 'batal': return 'Batal';
      default: return s;
    }
  }

  function bindEvents() {
    // Calendar navigation
    document.getElementById('cal-prev').addEventListener('click', () => {
      viewMonth--;
      if (viewMonth < 0) { viewMonth = 11; viewYear--; }
      render();
    });
    document.getElementById('cal-next').addEventListener('click', () => {
      viewMonth++;
      if (viewMonth > 11) { viewMonth = 0; viewYear++; }
      render();
    });

    // Calendar date click
    container.querySelectorAll('.cal-cell:not(.empty)').forEach(cell => {
      cell.addEventListener('click', function() {
        selectedDate = this.dataset.date;
        render();
      });
    });

    // Add appointment
    document.getElementById('btn-add-appt').addEventListener('click', showAddApptModal);

    // Appointment actions
    container.querySelectorAll('[data-action]').forEach(btn => {
      btn.addEventListener('click', function() {
        const action = this.dataset.action;
        const id = this.dataset.id;
        handleApptAction(action, id);
      });
    });
  }

  function showAddApptModal() {
    const html = `
      <div class="add-appt-modal">
        <h2>Buat Janji Baru</h2>
        <div class="form-group">
          <label>Nama *</label>
          <input type="text" id="appt-name" class="input" placeholder="Nama customer">
        </div>
        <div class="form-group">
          <label>No HP</label>
          <input type="tel" id="appt-phone" class="input" placeholder="08xx...">
        </div>
        <div class="form-group">
          <label>Tanggal *</label>
          <input type="date" id="appt-date" class="input" value="${selectedDate}">
        </div>
        <div class="form-group">
          <label>Jam *</label>
          <input type="time" id="appt-time" class="input" value="10:00">
        </div>
        <div class="form-group">
          <label>Barber</label>
          <select id="appt-barber" class="input">
            <option value="">Belum ditentukan</option>
            ${barbers.map(b => `<option value="${b.id}" data-name="${b.name}">${b.name}</option>`).join('')}
          </select>
        </div>
        <div class="form-group">
          <label>Layanan</label>
          <select id="appt-service" class="input">
            <option value="">Belum ditentukan</option>
            ${services.map(s => `<option value="${s.name}">${s.name} — ${rp(s.price)}</option>`).join('')}
          </select>
        </div>
        <div class="form-group">
          <label>Catatan</label>
          <input type="text" id="appt-notes" class="input" placeholder="Catatan tambahan...">
        </div>
        <div class="modal-actions">
          <button class="btn btn-secondary" id="appt-cancel">Batal</button>
          <button class="btn btn-primary" id="appt-save">Simpan</button>
        </div>
      </div>
    `;

    UI.showModal(html);

    document.getElementById('appt-cancel').addEventListener('click', () => UI.closeModal());
    document.getElementById('appt-save').addEventListener('click', () => {
      const name = document.getElementById('appt-name').value.trim();
      const phone = document.getElementById('appt-phone').value.trim();
      const date = document.getElementById('appt-date').value;
      const time = document.getElementById('appt-time').value;
      const barberSelect = document.getElementById('appt-barber');
      const barberId = barberSelect.value;
      const barberName = barberId ? barberSelect.options[barberSelect.selectedIndex].dataset.name : '';
      const service = document.getElementById('appt-service').value;
      const notes = document.getElementById('appt-notes').value.trim();

      if (!name) { UI.toast('Nama wajib diisi!', 'error'); return; }
      if (!date) { UI.toast('Tanggal wajib diisi!', 'error'); return; }
      if (!time) { UI.toast('Jam wajib diisi!', 'error'); return; }

      const allAppts = DB.get('appointments') || [];
      allAppts.push({
        id: generateId('appt'),
        name,
        phone,
        date,
        time,
        barberId,
        barberName,
        service,
        notes,
        status: 'menunggu',
        timestamp: Date.now()
      });
      DB.set('appointments', allAppts);

      UI.closeModal();
      UI.toast('Janji berhasil dibuat! 📅', 'success');

      // Refresh appointments array
      appointments.length = 0;
      allAppts.forEach(a => appointments.push(a));
      selectedDate = date;
      render();
    });
  }

  function handleApptAction(action, id) {
    const allAppts = DB.get('appointments') || [];
    const appt = allAppts.find(a => a.id === id);
    if (!appt) return;

    if (action === 'confirm') {
      appt.status = 'dikonfirmasi';
      DB.set('appointments', allAppts);
      UI.toast('Janji dikonfirmasi! ✅', 'success');
    } else if (action === 'done') {
      appt.status = 'selesai';
      DB.set('appointments', allAppts);
      UI.toast('Janji selesai! ✅', 'success');
    } else if (action === 'cancel') {
      appt.status = 'batal';
      DB.set('appointments', allAppts);
      UI.toast('Janji dibatalkan', 'info');
    } else if (action === 'delete') {
      const idx = allAppts.findIndex(a => a.id === id);
      if (idx >= 0) {
        allAppts.splice(idx, 1);
        DB.set('appointments', allAppts);
        UI.toast('Janji dihapus', 'info');
      }
    } else if (action === 'wa-remind') {
      const msg = `Halo ${appt.name}! Pengingat: jadwal potong kamu di ${shopName} hari ini jam ${appt.time}. Ditunggu ya! 💈`;
      const link = waLink(appt.phone, msg);
      window.open(link, '_blank');
      return;
    }

    // Refresh
    appointments.length = 0;
    allAppts.forEach(a => appointments.push(a));
    render();
  }

  // Use formatDateIndo from home.js or define locally
  if (typeof formatDateIndo === 'undefined') {
    window.formatDateIndo = function(dateStr) {
      const days = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];
      const months = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];
      const d = new Date(dateStr + 'T00:00:00');
      return `${days[d.getDay()]}, ${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
    };
  }

  render();
}

// member.js — Membership management
function renderMember(container) {
  const settings = DB.get('settings') || {};
  const shopName = (settings.shop && settings.shop.name) || 'Pangkas';
  const visitTarget = settings.memberVisits || 10;
  const reward = settings.memberReward || '1x Potong Gratis';

  let searchQuery = '';
  let viewMode = 'list'; // list | detail
  let selectedMemberId = null;

  function render() {
    const members = DB.get('members') || [];
    const today = new Date().toISOString().slice(0, 10);
    const todayMD = today.slice(5); // MM-DD

    // Filter by search
    let filtered = members;
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      filtered = members.filter(m =>
        m.name.toLowerCase().includes(q) || (m.phone && m.phone.includes(q))
      );
    }

    // Birthday members
    const todayBirthdays = members.filter(m => m.birthday && m.birthday.slice(5) === todayMD);
    const next7 = [];
    for (let i = 1; i <= 7; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      const md = d.toISOString().slice(5, 10);
      members.filter(m => m.birthday && m.birthday.slice(5) === md).forEach(m => next7.push(m));
    }

    if (viewMode === 'detail' && selectedMemberId) {
      renderDetail(container, selectedMemberId);
      return;
    }

    container.innerHTML = `
      <div class="page-member">
        <div class="page-header">
          <h2>👥 Member</h2>
          <button class="btn btn-primary" id="btn-add-member">+ Tambah</button>
        </div>

        <div class="search-bar">
          <input type="text" id="member-search" class="input" placeholder="🔍 Cari nama atau no HP..." value="${searchQuery}">
        </div>

        ${todayBirthdays.length > 0 ? `
          <div class="card birthday-card">
            <h3>🎂 Ulang Tahun Hari Ini!</h3>
            ${todayBirthdays.map(m => `
              <div class="birthday-item">
                <span><strong>${m.name}</strong> — Selamat Ulang Tahun! 🎉</span>
                ${m.phone ? `
                  <button class="btn btn-sm btn-outline" data-action="wa-birthday" data-id="${m.id}">📱 Kirim Ucapan</button>
                ` : ''}
              </div>
            `).join('')}
          </div>
        ` : ''}

        ${next7.length > 0 ? `
          <div class="card">
            <h3>🎂 Ulang Tahun 7 Hari ke Depan</h3>
            ${next7.map(m => `
              <div class="birthday-item">
                <span>${m.name} — ${m.birthday ? m.birthday.slice(5) : ''}</span>
                ${m.phone ? `
                  <button class="btn btn-sm btn-outline" data-action="wa-birthday" data-id="${m.id}">📱 Ucapan</button>
                ` : ''}
              </div>
            `).join('')}
          </div>
        ` : ''}

        <div class="member-list">
          ${filtered.length === 0 ? `
            <div class="empty-state"><p>Belum ada member. Tap "Tambah" untuk menambahkan.</p></div>
          ` : ''}
          ${filtered.map(m => {
            const visits = m.visits || 0;
            const progress = Math.min(visits, visitTarget);
            const isBirthday = m.birthday && m.birthday.slice(5) === todayMD;
            const canClaim = visits >= visitTarget;

            return `
              <div class="member-card card" data-id="${m.id}">
                <div class="member-main" data-action="view-detail" data-id="${m.id}">
                  <div class="member-name-row">
                    <strong>${m.name}</strong>
                    ${isBirthday ? '<span class="birthday-badge">🎂</span>' : ''}
                    ${canClaim ? '<span class="badge badge-success">🎁 Reward!</span>' : ''}
                  </div>
                  <span class="text-muted">${m.phone || 'No HP -'}</span>
                  <div class="visit-dots">
                    ${Array.from({length: visitTarget}, (_, i) => `
                      <span class="visit-dot ${i < progress ? 'filled' : ''}"></span>
                    `).join('')}
                    <span class="visit-count">${visits}/${visitTarget}</span>
                  </div>
                  <span class="text-muted text-sm">Kunjungan terakhir: ${m.lastVisit || '-'}</span>
                </div>
                <div class="member-actions">
                  <button class="btn btn-sm btn-outline" data-action="edit" data-id="${m.id}">✏️</button>
                  ${canClaim ? `<button class="btn btn-sm btn-success" data-action="claim" data-id="${m.id}">🎁 Klaim</button>` : ''}
                </div>
              </div>
            `;
          }).join('')}
        </div>
      </div>
    `;

    bindEvents();
  }

  function renderDetail(container, memberId) {
    const members = DB.get('members') || [];
    const member = members.find(m => m.id === memberId);
    if (!member) { viewMode = 'list'; render(); return; }

    const transactions = DB.get('transactions') || [];
    const memberTx = transactions.filter(t => t.memberId === memberId).sort((a, b) => b.timestamp - a.timestamp);
    const totalSpent = memberTx.reduce((s, t) => s + (t.total || 0), 0);

    container.innerHTML = `
      <div class="page-member-detail">
        <div class="page-header">
          <button class="btn btn-outline" id="btn-back-member">← Kembali</button>
          <h2>${member.name}</h2>
        </div>

        <div class="card">
          <div class="detail-info">
            <p><strong>📱 No HP:</strong> ${member.phone || '-'}</p>
            <p><strong>🎂 Tanggal Lahir:</strong> ${member.birthday || '-'}</p>
            <p><strong>📊 Total Kunjungan:</strong> ${member.visits || 0}</p>
            <p><strong>💰 Total Belanja:</strong> ${rp(totalSpent)}</p>
            <p><strong>📅 Kunjungan Terakhir:</strong> ${member.lastVisit || '-'}</p>
          </div>
        </div>

        <div class="card">
          <h3>Riwayat Transaksi</h3>
          ${memberTx.length === 0 ? '<p class="text-muted">Belum ada transaksi</p>' : ''}
          ${memberTx.map(t => `
            <div class="tx-item">
              <div class="tx-info">
                <span>${t.date} ${t.time || ''}</span>
                <span class="text-muted">${t.barberName || ''} • ${t.paymentMethod || ''}</span>
                <span class="text-sm">${(t.items || []).map(i => i.name).join(', ')}</span>
              </div>
              <div class="tx-amount">${rp(t.total || 0)}</div>
            </div>
          `).join('')}
        </div>
      </div>
    `;

    document.getElementById('btn-back-member').addEventListener('click', () => {
      viewMode = 'list';
      selectedMemberId = null;
      render();
    });
  }

  function bindEvents() {
    // Search
    document.getElementById('member-search').addEventListener('input', function() {
      searchQuery = this.value;
      render();
    });

    // Add member
    document.getElementById('btn-add-member').addEventListener('click', () => showMemberModal());

    // Actions
    container.querySelectorAll('[data-action]').forEach(el => {
      el.addEventListener('click', function(e) {
        e.stopPropagation();
        const action = this.dataset.action;
        const id = this.dataset.id;

        if (action === 'view-detail') {
          viewMode = 'detail';
          selectedMemberId = id;
          render();
        } else if (action === 'edit') {
          showMemberModal(id);
        } else if (action === 'claim') {
          claimReward(id);
        } else if (action === 'wa-birthday') {
          sendBirthdayWA(id);
        }
      });
    });
  }

  function showMemberModal(editId) {
    const members = DB.get('members') || [];
    const editing = editId ? members.find(m => m.id === editId) : null;

    const html = `
      <div class="member-modal">
        <h2>${editing ? 'Edit' : 'Tambah'} Member</h2>
        <div class="form-group">
          <label>Nama *</label>
          <input type="text" id="mem-name" class="input" placeholder="Nama member" value="${editing ? editing.name : ''}">
        </div>
        <div class="form-group">
          <label>No HP</label>
          <input type="tel" id="mem-phone" class="input" placeholder="08xx..." value="${editing ? (editing.phone || '') : ''}">
        </div>
        <div class="form-group">
          <label>Tanggal Lahir</label>
          <input type="date" id="mem-birthday" class="input" value="${editing ? (editing.birthday || '') : ''}">
        </div>
        <div class="modal-actions">
          <button class="btn btn-secondary" id="mem-cancel">Batal</button>
          <button class="btn btn-primary" id="mem-save">Simpan</button>
        </div>
      </div>
    `;

    UI.showModal(html);

    document.getElementById('mem-cancel').addEventListener('click', () => UI.closeModal());
    document.getElementById('mem-save').addEventListener('click', () => {
      const name = document.getElementById('mem-name').value.trim();
      const phone = document.getElementById('mem-phone').value.trim();
      const birthday = document.getElementById('mem-birthday').value;

      if (!name) { UI.toast('Nama wajib diisi!', 'error'); return; }

      const allMembers = DB.get('members') || [];

      if (editing) {
        const mem = allMembers.find(m => m.id === editId);
        if (mem) {
          mem.name = name;
          mem.phone = phone;
          mem.birthday = birthday;
        }
      } else {
        allMembers.push({
          id: generateId('mem'),
          name,
          phone,
          birthday,
          visits: 0,
          totalSpent: 0,
          lastVisit: null,
          createdAt: Date.now()
        });
      }

      DB.set('members', allMembers);
      UI.closeModal();
      UI.toast(editing ? 'Member diupdate! ✅' : 'Member ditambahkan! 👥', 'success');
      render();
    });
  }

  function claimReward(memberId) {
    const allMembers = DB.get('members') || [];
    const mem = allMembers.find(m => m.id === memberId);
    if (!mem) return;

    UI.showModal(`
      <div class="confirm-modal">
        <h3>🎁 Klaim Reward</h3>
        <p><strong>${mem.name}</strong> sudah ${mem.visits} kunjungan!</p>
        <p>Reward: <strong>${reward}</strong></p>
        <p>Reset hitungan kunjungan?</p>
        <div class="modal-actions">
          <button class="btn btn-secondary" id="claim-cancel">Batal</button>
          <button class="btn btn-primary" id="claim-confirm">Klaim & Reset</button>
        </div>
      </div>
    `);

    document.getElementById('claim-cancel').addEventListener('click', () => UI.closeModal());
    document.getElementById('claim-confirm').addEventListener('click', () => {
      mem.visits = 0;
      DB.set('members', allMembers);
      UI.closeModal();
      UI.toast(`Reward diklaim untuk ${mem.name}! 🎉`, 'success');
      render();
    });
  }

  function sendBirthdayWA(memberId) {
    const members = DB.get('members') || [];
    const mem = members.find(m => m.id === memberId);
    if (!mem || !mem.phone) return;

    const msg = `Halo ${mem.name}, Selamat Ulang Tahun! 🎂 Spesial buat kamu, ada hadiah dari kami di ${shopName}. Ditunggu ya!`;
    const link = waLink(mem.phone, msg);
    window.open(link, '_blank');
  }

  render();
}

// laporan.js — Reports
function renderLaporan(container) {
  const settings = DB.get('settings') || {};
  const commission = settings.commission || 40;
  let period = 'today'; // today | week | month | all

  function render() {
    const transactions = DB.get('transactions') || [];
    const expenses = DB.get('expenses') || [];
    const barbers = DB.get('barbers') || [];
    const today = new Date().toISOString().slice(0, 10);

    // Filter transactions by period
    const filtered = filterByPeriod(transactions, period);
    const filteredExpenses = filterByPeriod(expenses, period);

    // Stats
    const totalRevenue = filtered.reduce((s, t) => s + (t.total || 0), 0);
    const totalCommission = filtered.reduce((s, t) => s + (t.commission || 0), 0);
    const totalExpenses = filteredExpenses.reduce((s, e) => s + (e.total || 0), 0);
    const netRevenue = totalRevenue - totalCommission;
    const profit = netRevenue - totalExpenses;
    const txCount = filtered.length;

    // Hutang warning
    const unpaidTx = transactions.filter(t => t.paid === false);
    const totalHutang = unpaidTx.reduce((s, t) => s + (t.total || 0), 0);

    // Barber commission table
    const barberStats = {};
    barbers.forEach(b => {
      barberStats[b.id] = { name: b.name, txCount: 0, revenue: 0, commission: 0 };
    });
    filtered.forEach(t => {
      if (t.barberId && barberStats[t.barberId]) {
        barberStats[t.barberId].txCount++;
        barberStats[t.barberId].revenue += (t.total || 0);
        barberStats[t.barberId].commission += (t.commission || 0);
      }
    });

    // Bar chart data (last 7 days)
    const chartData = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const ds = d.toISOString().slice(0, 10);
      const dayTx = transactions.filter(t => t.date === ds);
      const dayRev = dayTx.reduce((s, t) => s + (t.total || 0), 0);
      const dayLabel = d.toLocaleDateString('id-ID', { weekday: 'short' });
      chartData.push({ date: ds, label: dayLabel, revenue: dayRev });
    }
    const maxRev = Math.max(...chartData.map(d => d.revenue), 1);

    container.innerHTML = `
      <div class="page-laporan">
        <div class="page-header">
          <h2>📊 Laporan</h2>
        </div>

        <div class="period-tabs">
          <button class="tab ${period === 'today' ? 'active' : ''}" data-period="today">Hari Ini</button>
          <button class="tab ${period === 'week' ? 'active' : ''}" data-period="week">Minggu</button>
          <button class="tab ${period === 'month' ? 'active' : ''}" data-period="month">Bulan</button>
          <button class="tab ${period === 'all' ? 'active' : ''}" data-period="all">Semua</button>
        </div>

        <div class="stat-cards">
          <div class="stat-card stat-revenue">
            <div class="stat-value">${rp(totalRevenue)}</div>
            <div class="stat-label">Pendapatan</div>
          </div>
          <div class="stat-card">
            <div class="stat-value">${rp(netRevenue)}</div>
            <div class="stat-label">Net (- Komisi)</div>
          </div>
          <div class="stat-card ${profit >= 0 ? 'stat-success' : 'stat-danger'}">
            <div class="stat-value">${rp(profit)}</div>
            <div class="stat-label">Profit (- Belanja)</div>
          </div>
          <div class="stat-card">
            <div class="stat-value">${txCount}</div>
            <div class="stat-label">Transaksi</div>
          </div>
        </div>

        ${totalHutang > 0 ? `
          <div class="card warning-card">
            ⚠️ Ada ${unpaidTx.length} hutang belum lunas: <strong>${rp(totalHutang)}</strong>
            <button class="btn btn-sm btn-outline" onclick="navigateTo('hutang')">Lihat →</button>
          </div>
        ` : ''}

        <div class="card">
          <h3>📊 Pendapatan 7 Hari Terakhir</h3>
          <div class="bar-chart">
            ${chartData.map(d => `
              <div class="bar-col">
                <div class="bar-value">${d.revenue > 0 ? rp(d.revenue) : ''}</div>
                <div class="bar" style="height: ${Math.max(4, (d.revenue / maxRev) * 150)}px;"></div>
                <div class="bar-label">${d.label}</div>
              </div>
            `).join('')}
          </div>
        </div>

        <div class="card">
          <h3>💈 Komisi Barber</h3>
          <div class="table-wrap">
            <table class="data-table">
              <thead>
                <tr><th>Barber</th><th>Transaksi</th><th>Pendapatan</th><th>Komisi (${commission}%)</th></tr>
              </thead>
              <tbody>
                ${Object.values(barberStats).map(b => `
                  <tr>
                    <td>${b.name}</td>
                    <td>${b.txCount}</td>
                    <td>${rp(b.revenue)}</td>
                    <td>${rp(b.commission)}</td>
                  </tr>
                `).join('')}
                ${Object.values(barberStats).length === 0 ? '<tr><td colspan="4">Belum ada data</td></tr>' : ''}
              </tbody>
            </table>
          </div>
        </div>

        <div class="card">
          <h3>🧾 Riwayat Transaksi</h3>
          <div class="table-wrap">
            <table class="data-table">
              <thead>
                <tr><th>Tanggal</th><th>Customer</th><th>Barber</th><th>Total</th><th>Bayar</th></tr>
              </thead>
              <tbody>
                ${filtered.sort((a, b) => b.timestamp - a.timestamp).slice(0, 50).map(t => `
                  <tr>
                    <td>${t.date || ''}</td>
                    <td>${t.customerName || 'Walk-in'}</td>
                    <td>${t.barberName || ''}</td>
                    <td>${rp(t.total || 0)}</td>
                    <td><span class="badge badge-sm">${t.paymentMethod || ''}</span></td>
                  </tr>
                `).join('')}
                ${filtered.length === 0 ? '<tr><td colspan="5">Belum ada transaksi</td></tr>' : ''}
              </tbody>
            </table>
          </div>
        </div>

        <div class="card">
          <h3>💾 Data & Export</h3>
          <div class="data-actions">
            <button class="btn btn-outline" id="btn-export-csv">📄 Export CSV</button>
            <button class="btn btn-outline" id="btn-backup-json">💾 Backup JSON</button>
            <div class="form-group">
              <label class="btn btn-outline" style="cursor:pointer;">
                📂 Import Backup
                <input type="file" id="btn-import-json" accept=".json" style="display:none;">
              </label>
            </div>
          </div>
        </div>
      </div>
    `;

    bindEvents();
  }

  function filterByPeriod(data, p) {
    const now = new Date();
    const today = now.toISOString().slice(0, 10);

    if (p === 'today') {
      return data.filter(d => (d.date || '').startsWith(today));
    } else if (p === 'week') {
      const weekAgo = new Date(now);
      weekAgo.setDate(weekAgo.getDate() - 7);
      const ws = weekAgo.toISOString().slice(0, 10);
      return data.filter(d => (d.date || '') >= ws);
    } else if (p === 'month') {
      const monthStr = today.slice(0, 7);
      return data.filter(d => (d.date || '').startsWith(monthStr));
    }
    return data; // all
  }

  function bindEvents() {
    // Period tabs
    container.querySelectorAll('.period-tabs .tab').forEach(tab => {
      tab.addEventListener('click', function() {
        period = this.dataset.period;
        render();
      });
    });

    // Export CSV
    document.getElementById('btn-export-csv').addEventListener('click', exportCSV);

    // Backup JSON
    document.getElementById('btn-backup-json').addEventListener('click', backupJSON);

    // Import JSON
    document.getElementById('btn-import-json').addEventListener('change', importJSON);
  }

  function exportCSV() {
    const transactions = DB.get('transactions') || [];
    let csv = 'Tanggal,Jam,Customer,Barber,Items,Total,Metode Bayar,Status\n';
    transactions.forEach(t => {
      const items = (t.items || []).map(i => i.name).join('; ');
      csv += `"${t.date || ''}","${t.time || ''}","${t.customerName || ''}","${t.barberName || ''}","${items}","${t.total || 0}","${t.paymentMethod || ''}","${t.paid ? 'Lunas' : 'Hutang'}"\n`;
    });

    downloadFile(csv, `pangkas-laporan-${new Date().toISOString().slice(0, 10)}.csv`, 'text/csv');
    UI.toast('CSV berhasil di-export! 📄', 'success');
  }

  function backupJSON() {
    const backup = {
      version: '1.0',
      date: new Date().toISOString(),
      settings: DB.get('settings'),
      barbers: DB.get('barbers'),
      services: DB.get('services'),
      addons: DB.get('addons'),
      members: DB.get('members'),
      transactions: DB.get('transactions'),
      queue: DB.get('queue'),
      appointments: DB.get('appointments'),
      expenses: DB.get('expenses')
    };

    const json = JSON.stringify(backup, null, 2);
    downloadFile(json, `pangkas-backup-${new Date().toISOString().slice(0, 10)}.json`, 'application/json');
    UI.toast('Backup berhasil! 💾', 'success');
  }

  function importJSON(e) {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = function(ev) {
      try {
        const data = JSON.parse(ev.target.result);
        if (!data.version) {
          UI.toast('File tidak valid!', 'error');
          return;
        }

        if (data.settings) DB.set('settings', data.settings);
        if (data.barbers) DB.set('barbers', data.barbers);
        if (data.services) DB.set('services', data.services);
        if (data.addons) DB.set('addons', data.addons);
        if (data.members) DB.set('members', data.members);
        if (data.transactions) DB.set('transactions', data.transactions);
        if (data.queue) DB.set('queue', data.queue);
        if (data.appointments) DB.set('appointments', data.appointments);
        if (data.expenses) DB.set('expenses', data.expenses);

        UI.toast('Data berhasil di-import! 🎉', 'success');
        render();
      } catch (err) {
        UI.toast('Error membaca file: ' + err.message, 'error');
      }
    };
    reader.readAsText(file);
  }

  function downloadFile(content, filename, mimeType) {
    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }

  render();
}

// hutang.js — Debt Tracking
function renderHutang(container) {
  let showPaid = false;

  function render() {
    const transactions = DB.get('transactions') || [];
    const settings = DB.get('settings') || {};
    const commission = settings.commission || 40;

    const unpaid = transactions.filter(t => t.paid === false).sort((a, b) => b.timestamp - a.timestamp);
    const paid = transactions.filter(t => t.paymentMethod === 'hutang' && t.paid === true).sort((a, b) => b.timestamp - a.timestamp);

    const totalUnpaid = unpaid.reduce((s, t) => s + (t.total || 0), 0);

    container.innerHTML = `
      <div class="page-hutang">
        <div class="page-header">
          <h2>📝 Hutang</h2>
        </div>

        <div class="card summary-card">
          <div class="hutang-summary">
            <div class="hutang-stat">
              <span class="hutang-count">${unpaid.length}</span>
              <span class="text-muted">Belum lunas</span>
            </div>
            <div class="hutang-stat">
              <span class="hutang-amount">${rp(totalUnpaid)}</span>
              <span class="text-muted">Total hutang</span>
            </div>
          </div>
        </div>

        ${unpaid.length === 0 ? `
          <div class="card empty-state">
            <p>Tidak ada hutang. Bersih! ✨</p>
          </div>
        ` : ''}

        <div class="hutang-list">
          ${unpaid.map(t => `
            <div class="hutang-card card">
              <div class="hutang-info">
                <div class="hutang-name-row">
                  <strong>${t.customerName || 'Walk-in'}</strong>
                  <span class="hutang-amount-badge">${rp(t.total || 0)}</span>
                </div>
                <span class="text-muted">Barber: ${t.barberName || '-'}</span>
                <span class="text-muted">📅 ${t.date || ''} ${t.time || ''}</span>
                ${t.hutangNote ? `<span class="text-muted">📝 ${t.hutangNote}</span>` : ''}
                <span class="text-sm text-muted">${(t.items || []).map(i => i.name).join(', ')}</span>
              </div>
              <div class="hutang-actions">
                <button class="btn btn-sm btn-success" data-action="lunas" data-id="${t.id}">✅ Lunas</button>
                ${currentUser && currentUser.role === 'admin' ? `
                  <button class="btn btn-sm btn-danger" data-action="delete" data-id="${t.id}">🗑️</button>
                ` : ''}
              </div>
            </div>
          `).join('')}
        </div>

        <div class="card" style="margin-top:1rem;">
          <div class="section-header" id="toggle-paid" style="cursor:pointer;">
            <h3>✅ Riwayat Lunas ${paid.length > 0 ? `(${paid.length})` : ''}</h3>
            <span>${showPaid ? '▲' : '▼'}</span>
          </div>
          ${showPaid ? `
            <div class="paid-list">
              ${paid.length === 0 ? '<p class="text-muted">Belum ada riwayat</p>' : ''}
              ${paid.map(t => `
                <div class="paid-item">
                  <div>
                    <strong>${t.customerName || 'Walk-in'}</strong>
                    <span class="text-muted">${t.date || ''}</span>
                  </div>
                  <span>${rp(t.total || 0)}</span>
                </div>
              `).join('')}
            </div>
          ` : ''}
        </div>
      </div>
    `;

    bindEvents();
  }

  function bindEvents() {
    // Toggle paid section
    const toggleBtn = document.getElementById('toggle-paid');
    if (toggleBtn) {
      toggleBtn.addEventListener('click', () => {
        showPaid = !showPaid;
        render();
      });
    }

    // Actions
    container.querySelectorAll('[data-action]').forEach(btn => {
      btn.addEventListener('click', function() {
        const action = this.dataset.action;
        const id = this.dataset.id;

        if (action === 'lunas') {
          markPaid(id);
        } else if (action === 'delete') {
          deleteHutang(id);
        }
      });
    });
  }

  function markPaid(txId) {
    const transactions = DB.get('transactions') || [];
    const tx = transactions.find(t => t.id === txId);
    if (!tx) return;

    tx.paid = true;
    tx.paidDate = new Date().toISOString().slice(0, 10);

    // Recalculate commission since now it's paid
    const settings = DB.get('settings') || {};
    const commissionPct = settings.commission || 40;
    tx.commission = Math.round((tx.total || 0) * commissionPct / 100);

    DB.set('transactions', transactions);
    UI.toast(`${tx.customerName || 'Walk-in'} sudah lunas! ✅`, 'success');
    render();
  }

  function deleteHutang(txId) {
    UI.showModal(`
      <div class="confirm-modal">
        <h3>Hapus Hutang?</h3>
        <p>Transaksi ini akan dihapus permanen.</p>
        <div class="modal-actions">
          <button class="btn btn-secondary" id="del-cancel">Batal</button>
          <button class="btn btn-danger" id="del-confirm">Hapus</button>
        </div>
      </div>
    `);

    document.getElementById('del-cancel').addEventListener('click', () => UI.closeModal());
    document.getElementById('del-confirm').addEventListener('click', () => {
      const transactions = DB.get('transactions') || [];
      const idx = transactions.findIndex(t => t.id === txId);
      if (idx >= 0) {
        transactions.splice(idx, 1);
        DB.set('transactions', transactions);
      }
      UI.closeModal();
      UI.toast('Hutang dihapus', 'info');
      render();
    });
  }

  render();
}

